function [rslt] = fFitGausV02(x,y,rat)% Perform fitting to Gaussian distribution%% [] = fFitGausV01(x,cnts,ratio)% x: axis information (x axis)% y: counts for each point (yaxis)% rat: difine threshold to fit, 0.2 will cut below 0.2 x peak%% rslt: structure with the fields%       sig^2,u          - fitted parameters%       CRB_sig2,CRB_u   - Cram?r-Rao Bound for the estimator value%       RMS              - RMS error of the estimation %       type             - 'ML'%       cff              - coefficient for distribution%%%%%%%%%%%%%%%%%%%%%%%%%%%%%% Fit Gaussian, ver.1%% Kei Nakamura% Created on Thursday, February 11th 2010.% Modified on %% ver.1: created% ver.2: fix cff%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:numel(x)],y,rat);    % for roix1 = round(peak-wLOut); x2 = round(peak+wHOut);fitY = y(x1:x2); fitX = x(x1:x2);    % roi for fitttlCnt = sum(fitY);  % total countshst = fGetHstV01(fitX,fitY);    % to get histogram for fittingrslt = fit_ML_normal(hst);uHigh = fitX(end) - rslt.u;     % width high sideuHighN = uHigh/sqrt(rslt.sig2);  % width in terms of number of sigmauLow = rslt.u - fitX(1);         % width low sideuLowN = uLow/sqrt(rslt.sig2);    % width in terms of number of sigmaerfH = 0.5*erf(uHighN/sqrt(2));       % integrated probability for high sideerfL = 0.5*erf(uLowN/sqrt(2));        % for low sidettlPrb = erfH+erfL;             % total probability in fitted regionfitTtlCnt = ttlCnt/ttlPrb;      % total counts including outside for fitted resultcff = (x(2)-x(1))*fitTtlCnt/sqrt(2*pi*rslt.sig2);rslt.cff = cff;             yRslt = cff*exp(-(fitX-rslt.u).^2/rslt.sig2);% figure(8)% plot(fitX,fitY,'ro')% hold on% plot(fitX,yRslt,'b-')% hold off% figure(2)
